// 1. Get the raw HTML string from the HTTP Request node
const html = $input.first().json.data;

// 2. Use Regex to find the hidden JSON inside the 'data-page' attribute
const match = html.match(/data-page="([^"]+)"/);

if (!match) {
  throw new Error("Could not find the tender data. The website structure might have changed.");
}

let jsonString = match[1];

// 3. Decode HTML entities (convert &quot; back to normal quotes ")
jsonString = jsonString.replace(/&quot;/g, '"')
                       .replace(/&amp;/g, '&')
                       .replace(/&#039;/g, "'")
                       .replace(/&lt;/g, '<')
                       .replace(/&gt;/g, '>');

// 4. Parse the hidden JSON data
const pageData = JSON.parse(jsonString);

// 5. Extract the tenders array from the JSON
const tenders = pageData.props.tenders.data;

// 6. Format the data into clean items for the next nodes
return tenders.map(tender => {
  return {
    json: {
      Title: tender.title,
      Link: `https://tender.2merkato.com/tenders/${tender.id}`,
      Company: tender.company ? tender.company.name_en : 'Unknown',
      ClosingDate: tender.bid_closing_date || 'N/A',
      PublishedAt: tender.published_at || 'N/A',
      ID: tender.id
    }
  };
});

// 1. Get the 15 fresh tenders from our scraper (Code1)
// Note: Make sure 'Code1' matches the exact name of your first Code node!
const freshTenders = $('Code1').all();

// 2. Get the list of already processed tenders from Google Sheets
const processedTenders = $input.all();

// 3. THE MAGIC FIX: If the sheet is empty, just pass all fresh tenders through!
if (processedTenders.length === 0) {
  console.log("Google Sheet is empty. Passing all fresh tenders through.");
  return freshTenders;
}

// 4. Create a list of IDs we've already seen
const processedIds = new Set(
  processedTenders.map(t => t.json.ID)
);

// 5. Filter: Keep only tenders whose ID is NOT in our processed list
const newTenders = freshTenders.filter(tender => {
  return !processedIds.has(tender.json.ID);
});

// 6. Log the results
console.log(`Found ${newTenders.length} new tenders out of ${freshTenders.length} total`);

return newTenders;

const items = $input.all();
const results = [];

for (const item of items) {
  const rawText = item.json.text || item.json.output || "";
  const match = rawText.match(/\{[\s\S]*\}/);

  if (match) {
    try {
      const parsedJson = JSON.parse(match[0]);
      results.push({ json: parsedJson });
    } catch (error) {
      results.push({ json: { error: "Parse failed", raw: rawText } });
    }
  }
}

return results;
